94	int main(void)
95	{
96	  /* Phase 1 (QEMU 1): seed inputs only. */
97	  init_matrices();
98	
99	  enter_vsim();
100	
101	  /* Phase 2 (vsim): RVV kernel only. No I/O permitted. */
102	  vmatmul_kernel();
103	
104	  exit_vsim();
105	
106	  /* Phase 3 (QEMU 2): scalar reference compare. */
107	  if (!scalar_matmul_verify()) {
108	    printf("rt_c_v_matmul: FAIL\n");
109	    fflush(stdout);
110	    return 1;
111	  }
112	  printf("rt_c_v_matmul: PASS\n");
113	  fflush(stdout);
114	  return 0;
115	}
